namespace sv_c95ef7d9625d49e7859a3462038ce28e.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@page "/board"
@rendermode InteractiveServer
@using sv_c95ef7d9625d49e7859a3462038ce28e.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar d-flex flex-wrap gap-3 mb-3">
        <span class="badge bg-secondary">Total: @allTasks.Count</span>
        <span class="badge bg-info text-dark">To Do: @CountByStatus("To Do")</span>
        <span class="badge bg-warning text-dark">In Progress: @CountByStatus("In Progress")</span>
        <span class="badge bg-success">Done: @CountByStatus("Done")</span>
        <span class="badge bg-danger">Overdue: @OverdueCount()</span>
    </div>

    <!-- Search -->
    <div class="mb-3" style="max-width: 400px;">
        <input type="text"
               class="form-control"
               placeholder="Search tasks by title…"
               @bind="searchQuery"
               @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board-container d-flex gap-3">
        @foreach (var column in columns)
        {
            var columnTasks = GetFilteredTasks(column);
            var colIndex = Array.IndexOf(columns, column);

            <div class="board-column flex-fill">
                <div class="column-header d-flex justify-content-between align-items-center p-2 rounded-top">
                    <h5 class="mb-0">@column</h5>
                    <span class="badge bg-light text-dark">@columnTasks.Count</span>
                </div>

                <div class="column-body p-2">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card card mb-2">
                            <div class="card-body p-2">
                                <h6 class="card-title mb-1">@task.Title</h6>
                                <p class="card-text text-muted mb-1 small">@task.Assignee</p>
                                <div class="d-flex justify-content-between align-items-center mb-1">
                                    <span class="badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                </div>
                                <div class="d-flex gap-1">
                                    @if (colIndex > 0)
                                    {
                                        var prevStatus = columns[colIndex - 1];
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                disabled="@isUpdating"
                                                @onclick="() => MoveTaskAsync(task.Id, prevStatus)">
                                            ← Move Left
                                        </button>
                                    }
                                    @if (colIndex < columns.Length - 1)
                                    {
                                        var nextStatus = columns[colIndex + 1];
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                disabled="@isUpdating"
                                                @onclick="() => MoveTaskAsync(task.Id, nextStatus)">
                                            Move Right →
                                        </button>
                                    }
                                </div>
                            </div>
                        </div>
                    }

                    @if (addingToColumn == column)
                    {
                        <div class="card mb-2 border-primary">
                            <div class="card-body p-2">
                                <input type="text" class="form-control form-control-sm mb-1"
                                       placeholder="Title" @bind="newTitle" />
                                <input type="text" class="form-control form-control-sm mb-1"
                                       placeholder="Assignee" @bind="newAssignee" />
                                <select class="form-select form-select-sm mb-1" @bind="newPriority">
                                    <option value="High">High</option>
                                    <option value="Medium">Medium</option>
                                    <option value="Low">Low</option>
                                </select>
                                <input type="date" class="form-control form-control-sm mb-1"
                                       @bind="newDueDate" />
                                @if (formError is not null)
                                {
                                    <div class="text-danger small mb-1">@formError</div>
                                }
                                <div class="d-flex gap-1">
                                    <button class="btn btn-primary btn-sm flex-fill"
                                            disabled="@isSaving"
                                            @onclick="SaveNewTaskAsync">
                                        @(isSaving ? "Saving…" : "Save")
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm flex-fill"
                                            disabled="@isSaving"
                                            @onclick="CancelAdd">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        </div>
                    }
                    else
                    {
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => StartAdd(column)">
                            + Add Task
                        </button>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private bool isLoading = true;
    private bool isUpdating;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? formError;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private int OverdueCount() =>
        allTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchQuery))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        isUpdating = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isUpdating = false;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
        formError = null;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
        formError = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || string.IsNullOrWhiteSpace(newAssignee))
        {
            formError = "Title and assignee are required.";
            return;
        }

        isSaving = true;
        formError = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);

            // CreateTaskAsync returns a task with default status; ensure it matches the column
            var finalTask = created.Status == addingToColumn
                ? created
                : created with { Status = addingToColumn! };

            if (finalTask.Status != created.Status)
            {
                await TaskService.UpdateTaskStatusAsync(finalTask.Id, finalTask.Status);
            }

            allTasks.Add(finalTask);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            formError = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

.board-container {
    overflow-x: auto;
    min-height: 400px;
}

.board-column {
    min-width: 260px;
    background: #f8f9fa;
    border-radius: 0.5rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    background: #e9ecef;
    font-weight: 600;
}

.column-body {
    flex: 1;
}

.task-card {
    transition: box-shadow 0.15s;
}

.task-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}

::deep .priority-high {
    background-color: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754;
    color: #fff;
}

.stats-bar .badge {
    font-size: 0.9rem;
    padding: 0.45em 0.75em;
}

