                                            disabled="@isSaving"
                                            @onclick="SaveNewTaskAsync">
                                        @(isSaving ? "Saving…" : "Save")
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm flex-fill"
                                            disabled="@isSaving"
                                            @onclick="CancelAdd">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        </div>
