+    {
+        addingToColumn = null;
+        formError = null;
+    }
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(newTitle) || string.IsNullOrWhiteSpace(newAssignee))
+        {
+            formError = "Title and assignee are required.";
+            return;
+        }
+
+        isSaving = true;
+        formError = null;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
+
+            // CreateTaskAsync returns a task with default status; ensure it matches the column
+            var finalTask = created.Status == addingToColumn
+                ? created
+                : created with { Status = addingToColumn! };
+
+            if (finalTask.Status != created.Status)
+            {
+                await TaskService.UpdateTaskStatusAsync(finalTask.Id, finalTask.Status);
+            }
+
+            allTasks.Add(finalTask);
+            addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            formError = ex.Message;
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
