+                                    <span class="badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
+                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                </div>
+                                <div class="d-flex gap-1">
+                                    @if (colIndex > 0)
+                                    {
+                                        var prevStatus = columns[colIndex - 1];
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                disabled="@isUpdating"
+                                                @onclick="() => MoveTaskAsync(task.Id, prevStatus)">
+                                            ← Move Left
+                                        </button>
+                                    }
+                                    @if (colIndex < columns.Length - 1)
+                                    {
+                                        var nextStatus = columns[colIndex + 1];
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                disabled="@isUpdating"
+                                                @onclick="() => MoveTaskAsync(task.Id, nextStatus)">
+                                            Move Right →
+                                        </button>
+                                    }
+                                </div>
+                            </div>
+                        </div>
+                    }
+
