.board-container {
    overflow-x: auto;
    min-height: 400px;
}

.board-column {
    min-width: 260px;
    background: #f8f9fa;
    border-radius: 0.5rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    background: #e9ecef;
    font-weight: 600;
}

.column-body {
    flex: 1;
}

.task-card {
    transition: box-shadow 0.15s;
}

.task-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}

::deep .priority-high {
    background-color: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754;
    color: #fff;
}

.stats-bar .badge {
    font-size: 0.9rem;
    padding: 0.45em 0.75em;
}

